import{_ as r,k as e,p as i,ac as p}from"./chunks/framework.DA7r4KNg.js";const m=JSON.parse('{"title":"手机端使用的方法","description":"","frontmatter":{},"headers":[],"relativePath":"hanxin/quanpin/shouji.md","filePath":"hanxin/quanpin/shouji.md"}'),t={name:"hanxin/quanpin/shouji.md"};function o(n,a,h,s,u,l){return i(),e("div",null,a[0]||(a[0]=[p('<h1 id="shouji-fangfa" tabindex="-1">手机端使用的方法 <a class="header-anchor" href="#shouji-fangfa" aria-label="Permalink to &quot;手机端使用的方法 {#shouji-fangfa}&quot;">​</a></h1><h2 id="guazhuyu" tabindex="-1"><strong>第一种是挂到短语里</strong> <a class="header-anchor" href="#guazhuyu" aria-label="Permalink to &quot;**第一种是挂到短语里** {#guazhuyu}&quot;">​</a></h2><p>1,推荐手心输入法手机版的</p><p><a href="https://www.bilibili.com/video/BV1U94y1V71V" target="_blank" rel="noreferrer">视频演示手心手机汉心辅怎么装</a></p><p>手心能导入的更多。而且导入起来更容易。</p><p>方法就是设置里找到自定义短语导入即可。</p><p>短语都是带数字和=于号的。就是短语辅助码。</p><p>手心直接是文本txt格式就可以.</p><hr><p>2,苹果只能用仓输入法导入了。</p><hr><p>3,百度输入法</p><p><a href="https://www.ixigua.com/7231103593359605812" target="_blank" rel="noreferrer">视频观看百度手机挂码</a></p><p>是找到手机输入法设置里,找到自定义短语或者词语,点击导入码表就可以 然后百度导入的格式要是.ini文件,文本格式要是utf16 lbe格式的</p><p>给导入到百度输入法的输入法短语里</p><p>注意,不要是定制版的输入法,定制版的输入法很难找到ini文件。</p><p>要去市场上重新下百度</p><p>百度输入法的好处可以用汉心大键盘，满键盘。打字更不容易误触。</p><p>手心就用不了，手心可以导入100万条。百度只能导入6万条短语辅助码。</p><p>搜狗手机只能导入500条，所以搜狗手机用不了。讯飞也只能导入几千条，也用不了。</p><hr><h2 id="mabiaodao-ru" tabindex="-1"><strong>第二种是码表导入到自定义五笔里</strong> <a class="header-anchor" href="#mabiaodao-ru" aria-label="Permalink to &quot;**第二种是码表导入到自定义五笔里** {#mabiaodao-ru}&quot;">​</a></h2><p>搜狗和百度都可以</p><p>这种是四码上屏,使用习惯需要适应一下.而且是小词库 四键上屏的意思,就是不管再长的句子,只能打4个键.成语也是4个键.</p><p>搜狗手机：①输入法设置里→输入设置→五笔输入→管理五笔方案→自定义五笔方案→任选一方案→管理→导入五笔方案→选择本文件 ②关闭“Z键作为五笔通配按键”，关闭“用户词库”，关闭“兼容系统词库”，关闭“五笔拼音混输” ③切换五笔键盘使用 ④不支持符号编码，可删除此部分编码 百度手机：①输入法设置里→输入设置→五笔输入→管理自定义方案→导入自定义输入方案→选择本文件 ②关闭“五笔拼音混输” ③切换五笔键盘使用 ④iOS如发现z键为通配符，请换个皮肤使用，直到z键不是通配符为止</p><hr><h2 id="rime-shouji" tabindex="-1"><strong>第三种是rime手机版输入法</strong> <a class="header-anchor" href="#rime-shouji" aria-label="Permalink to &quot;**第三种是rime手机版输入法** {#rime-shouji}&quot;">​</a></h2><p>1,安卓先手机下载同文输入法,也就是小狼毫安卓版,苹果用仓输入法. 2,把小狼毫配置文件就放入到对应的文件夹里.然后部署一下就可以用了.</p><p>苹果手机就是下载仓输入法然后导入rime小狼毫的包</p><p>注，小狼毫的配置包全平台通用。</p><p>具体网盘里找手机版相关教程</p>',31)]))}const c=r(t,[["render",o]]);export{m as __pageData,c as default};
